import datetime  # use to add to the time stamp in packet
import random    # use for seeding
from socket import *     # include this
import sys


# Player class contains data and methods used for maintaining game state.
class player:
    # Constructor initializes all variables
    def __init__(self, playerID):
        self.playerID = playerID  # player ID number
        self.playerIPaddress = None  # empty string for now
        self.lastTimePlayed = datetime.datetime(year=1970)  # time stamp of last played
        self.inGame = False        # True if in a game. False otherwise

    def setIPaddress(self, playerIP):    # method to change IP address field
        self.playerIPaddress = playerIP


# Game class is used to track player status and game data. It maintains list of players in game. Also provides a function to find a free player ID for new players.
class game:
    def __init__(self, maxPlayers):  # Constructor takes maximum number of players
        self.playerArray = []        # array to keep track of player state
        self.gameID = random.randint(1000000, 9999999)    # randomly generated 7 digit game ID
        self.maxPlayers = maxPlayers     # Maximum number of players that can play in a game

    def findFreePlayerNumber(self):      # Find free player number for new player based on current game state
        lowestNumber = None               # used to return first available playerID
        for i in range (0, len(self.playerArray)):
            if not self.playerArray[i].inGame:  # check to see is that entry contains player
                if lowestNumber == None or int(lowestNumber) > int(self.playerArray[i].playerID):
                    lowestNumber = self.playerArray[i].playerID
        return lowestNumber

    def addPlayerToGame(self, playerID, ipAddress):    # add a new player to array of player objects
        newPlayer = player(playerID)                   # create player object using constructor
        if int(newPlayer.playerID) > len(self.playerArray):
            self.playerArray.append(newPlayer)         # append it to end of list (add at end of list)

        self.playerArray[int(playerID)].setIPaddress(ipAddress)    # set player ip address based on passed in IP address

    def removePlayerFromGame(self, playerID):      # removes a player from array
        del self.playerArray[int(playerID)]        # delete the player ID that is passed into function


# GameStatus class defines methods and data for status server response. It is used as an argument to statusServer class constructor method.
class gameStatus:
    def __init__(self, numPlayersInGame):     # Constructor
        self.numPlayers = str(numPlayersInGame)        # number of players in the current game

    def getStatus(self):                       # function that returns game status as string for UDP response
        return "Current game ID is %s. %s player(s)" % (self.gameID, int(self.numPlayers))


# StatusServer class defines main method which runs status server for GameStatus class instance created in main. Takes a Game object and GameStatus object as arguments to run. This is the primary implementation of TCP/UDP protocol.
class statusServer:
    def __init__(self, game):          # Constructor for Status Server. Takes Game object passed into it
        self.gameObj = game            # initialize the Game class instance field

    def main(self, statusObj):         # Main method for this UDP/TCP server to run. It takes a statusObject as argument. This object has the function getStatus() that defines format of response packet
        sockobj = socket(AF_INET, SOCK_DGRAM)  # define UDP socket object
        #sockobj2 = socket(AF_INET, SOCK_STREAM)    # define TCP Socket Object
        portNum = random.randint(10350, 97648)     # randomly generated port number for use with UDP
        #portNum2 = 9700                            # randomly generated port numnber for use with TCP. This is used because port 9700 is blocked on my PC
        sockobj.bind(('', portNum))       # bind the UDP socket object to the randomly generated port number

        print("Status server started, listening on port %s and game ID: %s" %(portNum, self.gameObj.gameID))    # print statements
        #sockobj2.connect(('localhost', 9700))   # connect TCP socket to port 9700 of my PC for testing. This is commented out because I have blocked this TCP port on my PC

        try:
            while True:
                data, ipAddress = sockobj.recvfrom(1024)          # receive from UDP server
                print("UDP packet received from %s. Data length is %s" %(ipAddress, len(data)))

                if int(len(self.gameObj.playerArray)) == 1 and self.gameObj.playerArray[0].inGame:    # if only one player left in game
                    print("Only one player remaining")
                else:
                    print("%s players currently playing" %int(len(self.gameObj.playerArray)))

                if data[:4] != "quit":        # check for quit request and if not, provide full player list and game state based on current game state of server
                    sockobj.sendto(statusObj.getStatus().encode('utf-8'), ipAddress)     # send UDP response packet based on getStatus() method implementation
                else:                       # quit request received from TCP/UDP client. Server quits after 10 seconds delay and closes connection to stop CPU hogging.
                    print("Server is being stopped")

                #sockobj2.send(statusObj.getStatus().encode('utf-8'))     # send packet for TCP response. This is commented out because I have blocked this TCP port on my PC
                #print("%s players currently playing" %int(len(self.gameObj.playerArray)))
        except:
            pass


if __name__ == "__main__":

    maxPlayers = 5         # maximum number of players to accept in a game
    statusServerObj = None  # Status server class instance is not created here because it takes a Game object and GameStatus object as arguments which will be passed from main method call down in this file.
    gobj1 = None            # Game object instance variable used for TCP response

    # Main loop to start multiple instances of the status server.
    while True:

        gobj2 = game(maxPlayers)     # Create a new Game instance with maximum number of players defined above
        try:
            statusServerObj = statusServer(gobj2)  # create Status Server object by passing in created game object as argument to it. This will then provide all necessary information for UDP/TCP server response packet based on getStatus() method implementation

            gobj1 = gobj2        # assign the Game instance variable so that it is accessible from main() method of TCP/UDP status server class
            print("Game number %s created" %gobj1.gameID)

        except:
            maxPlayers += 5      # if maxplayers > 5, then create new game with 5 more players and start the status server. MaxPlayers = 5, 10, 15 etc.
            print("New Game with ID is %s. Current maximum number of players are %s" %(maxPlayers + 4, maxPlayers))

